import{_ as t,o as a,c as o,a3 as d}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Tenant API v1 — Notifications","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant API v1 — Notifications | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/api/tenant-v1-notifications"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant API v1 — Notifications | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/api/tenant-v1-notifications"}]]},"headers":[],"relativePath":"api/tenant-v1-notifications.md","filePath":"api/tenant-v1-notifications.md","lastUpdated":1784377329000}'),i={name:"api/tenant-v1-notifications.md"};function n(s,e,r,c,u,l){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="tenant-api-v1-—-notifications" tabindex="-1">Tenant API v1 — Notifications <a class="header-anchor" href="#tenant-api-v1-—-notifications" aria-label="Permalink to &quot;Tenant API v1 — Notifications&quot;">​</a></h1><p>Base path: <code>/api/tenant/v1</code></p><p>Middleware: <code>auth:tenant-api</code>, <code>tenant.user</code>, <code>verified</code>. Authorization: <code>dashboard.view</code> (via Gate on each action).</p><p>Laravel database notifications (<code>notifications</code> table). Architecture: <a href="/developer-guide/notification-architecture-contract">Notification Architecture Contract</a>.</p><p>Realtime: Laravel Reverb private channel <code>tenant.{tenantId}.user.{userId}</code> (event <code>NotificationCreated</code>). SPA uses Echo as primary and polls every 90 seconds only while Echo is disconnected.</p><h2 id="list-unread" tabindex="-1">List &amp; unread <a class="header-anchor" href="#list-unread" aria-label="Permalink to &quot;List &amp; unread&quot;">​</a></h2><h3 id="get-notifications" tabindex="-1">GET <code>/notifications</code> <a class="header-anchor" href="#get-notifications" aria-label="Permalink to &quot;GET `/notifications`&quot;">​</a></h3><p>Paginated notifications for the authenticated user.</p><p>Transformed item shape:</p><table tabindex="0"><thead><tr><th>Field</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>Stable notification UUID (Laravel <code>notifications.id</code>)</td></tr><tr><td><code>type</code></td><td>Prefer <code>data.type</code> when present, else notification class</td></tr><tr><td><code>data</code></td><td>Versioned envelope (<code>schema_version: 1</code>) — title, body, category, delivery, source, <strong>route descriptor</strong> (never SPA URLs), dedupe_key, entity refs.</td></tr><tr><td><code>read_at</code></td><td>Nullable timestamp</td></tr><tr><td><code>created_at</code></td><td></td></tr></tbody></table><h3 id="get-notifications-unread-count" tabindex="-1">GET <code>/notifications/unread-count</code> <a class="header-anchor" href="#get-notifications-unread-count" aria-label="Permalink to &quot;GET `/notifications/unread-count`&quot;">​</a></h3><p><code>{ &quot;count&quot;: number }</code></p><h2 id="mark-read" tabindex="-1">Mark read <a class="header-anchor" href="#mark-read" aria-label="Permalink to &quot;Mark read&quot;">​</a></h2><h3 id="post-notifications-id-read" tabindex="-1">POST <code>/notifications/{id}/read</code> <a class="header-anchor" href="#post-notifications-id-read" aria-label="Permalink to &quot;POST `/notifications/{id}/read`&quot;">​</a></h3><p>Marks a single notification read. 404 if not found for the current user.</p><h3 id="post-notifications-read-all" tabindex="-1">POST <code>/notifications/read-all</code> <a class="header-anchor" href="#post-notifications-read-all" aria-label="Permalink to &quot;POST `/notifications/read-all`&quot;">​</a></h3><p>Marks all unread notifications for the current user as read.</p><h2 id="channels-producers" tabindex="-1">Channels &amp; producers <a class="header-anchor" href="#channels-producers" aria-label="Permalink to &quot;Channels &amp; producers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Channels (v1)</th></tr></thead><tbody><tr><td><code>lead.assigned</code> / <code>lead.reassigned</code></td><td><code>database</code>, <code>broadcast</code>, <code>webpush</code></td></tr><tr><td><code>lead.assigned.digest</code></td><td><code>database</code>, <code>broadcast</code>, <code>webpush</code> (bulk/import via NotificationBatch)</td></tr><tr><td>Follow-up created / due / overdue</td><td><code>mail</code>, <code>database</code></td></tr><tr><td>Task assigned</td><td><code>mail</code>, <code>database</code>, <code>webpush</code></td></tr><tr><td>Task status / due</td><td><code>mail</code>, <code>database</code></td></tr></tbody></table><h3 id="aggregation" tabindex="-1">Aggregation <a class="header-anchor" href="#aggregation" aria-label="Permalink to &quot;Aggregation&quot;">​</a></h3><p>Bulk assign and import equal-distribution wrap <code>NotificationBatch</code>: per-lead assigns still audit, but notify is suppressed until flush — <strong>one digest (or single if count===1) per assignee</strong>. Idempotent via <code>data.dedupe_key</code>.</p><h3 id="scheduled-due-digests" tabindex="-1">Scheduled due digests <a class="header-anchor" href="#scheduled-due-digests" aria-label="Permalink to &quot;Scheduled due digests&quot;">​</a></h3><p><code>crm:send-due-notifications</code> (hourly) walks tenants and sends idempotent due/overdue notifications (daily <code>dedupe_key</code>).</p><h3 id="retention" tabindex="-1">Retention <a class="header-anchor" href="#retention" aria-label="Permalink to &quot;Retention&quot;">​</a></h3><p><code>notifications:prune --days=90</code> (weekly schedule) deletes <strong>read</strong> notifications older than N days. Unread are never pruned.</p><h3 id="broadcast-auth" tabindex="-1">Broadcast auth <a class="header-anchor" href="#broadcast-auth" aria-label="Permalink to &quot;Broadcast auth&quot;">​</a></h3><p><code>POST /broadcasting/auth</code> — middleware <code>tenancy</code>, <code>auth:tenant-api</code>, <code>tenant.user</code>. Channel class: <code>App\\Broadcasting\\TenantUserChannel</code>.</p><h2 id="web-push-subscriptions" tabindex="-1">Web Push subscriptions <a class="header-anchor" href="#web-push-subscriptions" aria-label="Permalink to &quot;Web Push subscriptions&quot;">​</a></h2><p>Standards-based Web Push (VAPID). Subscriptions belong to the authenticated tenant user. Duplicate <code>endpoint</code> values upsert.</p><h3 id="get-push-subscriptions-vapid-public-key" tabindex="-1">GET <code>/push-subscriptions/vapid-public-key</code> <a class="header-anchor" href="#get-push-subscriptions-vapid-public-key" aria-label="Permalink to &quot;GET `/push-subscriptions/vapid-public-key`&quot;">​</a></h3><p>Returns <code>{ public_key, subject, configured }</code>. Never exposes the private key.</p><h3 id="post-push-subscriptions" tabindex="-1">POST <code>/push-subscriptions</code> <a class="header-anchor" href="#post-push-subscriptions" aria-label="Permalink to &quot;POST `/push-subscriptions`&quot;">​</a></h3><p>Body:</p><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Notes</th></tr></thead><tbody><tr><td><code>endpoint</code></td><td>yes</td><td>Push service URL (max 500)</td></tr><tr><td><code>public_key</code></td><td>yes</td><td>p256dh</td></tr><tr><td><code>auth_token</code></td><td>yes</td><td></td></tr><tr><td><code>content_encoding</code></td><td>no</td><td><code>aes128gcm</code> (default) or <code>aesgcm</code></td></tr><tr><td><code>user_agent</code></td><td>no</td><td></td></tr></tbody></table><h3 id="put-push-subscriptions" tabindex="-1">PUT <code>/push-subscriptions</code> <a class="header-anchor" href="#put-push-subscriptions" aria-label="Permalink to &quot;PUT `/push-subscriptions`&quot;">​</a></h3><p>Refresh/update keys for an endpoint (same body as POST; upsert semantics).</p><h3 id="delete-push-subscriptions" tabindex="-1">DELETE <code>/push-subscriptions</code> <a class="header-anchor" href="#delete-push-subscriptions" aria-label="Permalink to &quot;DELETE `/push-subscriptions`&quot;">​</a></h3><p>Body: <code>{ &quot;endpoint&quot;: &quot;...&quot; }</code>. 404 if the endpoint is not owned by the current user.</p><h2 id="future-hooks-only" tabindex="-1">Future (hooks only) <a class="header-anchor" href="#future-hooks-only" aria-label="Permalink to &quot;Future (hooks only)&quot;">​</a></h2><ul><li>Per-user preferences (in-app / browser / email)</li><li><code>delivery: scheduled</code> digests</li><li>SMS / webhooks / FCM / APNs as additional Laravel channels using <code>PlatformNotificationPayloadMapper</code></li></ul>',40)])])}const b=t(i,[["render",n]]);export{p as __pageData,b as default};
